+    "gpt-4.1",
+    "gpt-5-mini",
+    "gpt-5.4-mini",
+    "gpt-5.1",
+    "gpt-5.2",
+    "gpt-5.3-codex",
+    "gpt-5.1-codex",
+    "gpt-5",
+    "gpt-5.4",
+    "gpt-5.1-codex-max",
