+  const confusedPhrases = [
+    "i'm not sure",
+    "i'm confused",
+    "unclear",
+    "not clear",
+    "i don't",
+    "cannot proceed",
+    "stuck",
+    "unable to",
+    "let me try",
+    "let me re-attempt",
+  ];
+  if (includesAny(text, confusedPhrases)) {
+    signals.push("agent-confusion-acknowledgment");
+  }
