// Regression tests for prompt-classification heuristics in the model-router extension.
// Uses only Node built-ins: node:test + node:assert.
// Run with: node --test tests/classify.test.mjs

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import {
  classifyPrompt,
  isExplicitReviewRequest,
  isToolHeavy,
  isComplexOrchestration,
  matchesPattern,
  normalizePrompt,
} from "../.github/extensions/model-router/classify.mjs";

// ---------------------------------------------------------------------------
// 1. Explicit review detection
// ---------------------------------------------------------------------------

describe("isExplicitReviewRequest", () => {
  it("detects bare 'review'", () => {
    assert.ok(isExplicitReviewRequest("review my implementation"));
  });

  it("detects 'code review'", () => {
    assert.ok(isExplicitReviewRequest("do a code review of this PR"));
  });

  it("detects 'audit'", () => {
    assert.ok(isExplicitReviewRequest("audit the authentication module"));
  });

  it("detects 'pr review'", () => {
    assert.ok(isExplicitReviewRequest("PR review for the new feature branch"));
  });

  it("detects 'find bugs'", () => {
    assert.ok(isExplicitReviewRequest("find bugs in the payment service"));
  });

  it("detects 'regression hunt'", () => {
