+    // complexity=0 here (short, no file paths, no complexity indicators), so tier stays builder
+    assert.notEqual(result.tier, "reasoning");
+  });
+
+  it("bare 'orchestration' without multi-word phrase does not trigger escalation", () => {
+    const result = classifyPrompt("implement the orchestration layer for the workflow");
+    // "orchestration" alone is not in ORCHESTRATION_KEYWORDS → no escalation
+    assert.equal(result.kind, "implementation");
+    // Should be builder (default for impl) not reasoning
+    assert.equal(result.tier, "builder");
+  });
+});
+
+// ---------------------------------------------------------------------------
+// 4. Word-boundary guard (matchesPattern)
+// ---------------------------------------------------------------------------
+
+describe("matchesPattern – word-boundary awareness", () => {
+  it("'fix' does not match inside 'prefix'", () => {
+    assert.ok(!matchesPattern("prefix the function name", "fix"));
+  });
+
+  it("'fix' does not match inside 'suffix'", () => {
+    assert.ok(!matchesPattern("add a suffix to the output", "fix"));
+  });
+
+  it("'change' does not match inside 'exchange'", () => {
+    assert.ok(!matchesPattern("exchange the tokens", "change"));
+  });
+
+  it("'call' does not match inside 'callback'", () => {
+    assert.ok(!matchesPattern("register a callback function", "call"));
+  });
+
+  it("'run' does not match inside 'truncate'", () => {
+    assert.ok(!matchesPattern("truncate the table", "run"));
+  });
+
+  it("'fix' does match as a standalone word", () => {
+    assert.ok(matchesPattern("fix the broken test", "fix"));
+  });
+
+  it("multi-word patterns use substring matching (no boundary requirement)", () => {
+    assert.ok(matchesPattern("parallel agents are running", "parallel agents"));
+  });
+});
